import{_ as e,o,c as t,a}from"./app.933e0b6e.js";const k=JSON.parse(`{"title":"TheOrangeWizard v. Quauhtli'n'Mia, Jul 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/theorangewizard_v_quauhtli_n_mia_jul_2018.md","lastUpdated":1666477380000}`),l={name:"government/court-cases-precedents/theorangewizard_v_quauhtli_n_mia_jul_2018.md"},i=a('<h1 id="theorangewizard-v-quauhtli-n-mia-jul-2018" tabindex="-1">TheOrangeWizard v. Quauhtli&#39;n&#39;Mia, Jul 2018 <a class="header-anchor" href="#theorangewizard-v-quauhtli-n-mia-jul-2018" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With Oddish presiding, TheOrangeWizard charged Quauhtli&#39;n&#39;Mia with Armour Damage, Theft, and Murder, demanding 256 diamonds in restitution. Quauhtli&#39;n&#39;Mia was ordered to return TheOrangeWizard&#39;s items.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>requesting 256d in reparations for armour damage, stolen equipment, and death</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/473453667454943232/2018-07-30_23.15.15.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/473453667454943232/2018-07-30_23.15.15.png</a></p></blockquote><p><strong>bgbba</strong>:</p><blockquote><p>Quauhtli&#39;n&#39;Mia Choose your judge please.</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>Oddish</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>ok @orange wizard can you please state what you are suing for</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>i did</p></blockquote><blockquote><p>256d in reparations</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>and what are you asking for reps for specificly</p></blockquote><blockquote><p>asin present your case my dude</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>quau killed me and took my gear</p></blockquote><blockquote><p>which was an e5u3st pick, e4u3 shovel, e5u3 axe, all named, as well as a pair of p4u3ds3ff4 boots, junk prot pants/chest/hat, significant durability damage, and about 40 steaks</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>ok</p></blockquote><blockquote><p>Quauhtli&#39;n&#39;Mia since the evidence for you killing orange is listed above i wont ask you to confirm or deny that you killed orange, but can you tell me why you did it</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>He came to NYC asking to live here, I told him that only people who havnt already lived in Yoahtl can live in or around Axochitlan; the only exception being dr_oracle.</p></blockquote><blockquote><p>I was somewhat receptive</p></blockquote><blockquote><p>however he made his mt doom, I told him noone was able to live in mt doom</p></blockquote><blockquote><p>Despite being told he could not live there he&#39;d say in VC that it was his; around the third time I was sure he was memeing around</p></blockquote><blockquote><p>regardless I know memeing is usually half-rooted in truth</p></blockquote><blockquote><p>I wouldnt stand for it</p></blockquote><blockquote><p>So I told him to leave</p></blockquote><blockquote><p>did it for like 30 minutes</p></blockquote><blockquote><p>I kept wacking him with a sword telling him to leave</p></blockquote><blockquote><p>even once trapped him in a hole</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/473590620716531725/2018-07-30_04.09.39.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/473590620716531725/2018-07-30_04.09.39.png</a></p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/473590624176832515/2018-07-30_04.09.41.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/473590624176832515/2018-07-30_04.09.41.png</a></p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/473590627389669376/2018-07-30_04.10.39.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/473590627389669376/2018-07-30_04.10.39.png</a></p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>if your telling him to leave why would you trap him preventing him to leave</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>This is him trying to get out</p></blockquote><blockquote><p>Well by now I was pretty sure he was memeing</p></blockquote><blockquote><p>So I thought &quot;hey I can have some fun too&quot;</p></blockquote><blockquote><p>didnt take him long to get out</p></blockquote><blockquote><p>the bastions in mt doom werent really working so he just built his way out</p></blockquote><blockquote><p>albiet he had to break some of the slabs to do it</p></blockquote><blockquote><p>as youcan see</p></blockquote><blockquote><p>however when he got out</p></blockquote><blockquote><p>he still wouldnt leave</p></blockquote><blockquote><p>by now I had to get serious</p></blockquote><blockquote><p>I wacked him off the island, (knockback sword)</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>and he died</p></blockquote><p><strong>Quauhtli&#39;n&#39;Mia</strong>:</p><blockquote><p>nah</p></blockquote><blockquote><p>he landed in the ocean</p></blockquote><blockquote><p>twice</p></blockquote><blockquote><p>i did this tweice</p></blockquote><blockquote><p>and he swam back</p></blockquote><blockquote><p>I really didnt want to kill him</p></blockquote><blockquote><p>but I would if he kept memeing too close to the sun</p></blockquote><blockquote><p>so I warned him one final time</p></blockquote><blockquote><p>&quot;I will legitmately kill you, if you do not leave&quot;</p></blockquote><blockquote><p>he kept coming</p></blockquote><blockquote><p>so I killed him</p></blockquote><blockquote><p>So post-mortem; he asked about his stuff</p></blockquote><blockquote><p>I told him its mine, this was me memeing back</p></blockquote><blockquote><p>Im kind of suprisedhe couldnt tell</p></blockquote><blockquote><p>:&gt;</p></blockquote><blockquote><p>so I let up after a bit</p></blockquote><blockquote><p>and told him i&#39;d be halfway through the rails</p></blockquote><blockquote><p>( or what WOULD be rails)</p></blockquote><blockquote><p>to give him his stuff</p></blockquote><blockquote><p>he told me that because I killed him i need to come all the way to axo to give him his stuff</p></blockquote><blockquote><p>naturally, I thought this was a bit wierd and wierd</p></blockquote><blockquote><p>then orange left</p></blockquote><blockquote><p>he had to go to bed</p></blockquote><blockquote><p>and after that I had to got to bed too</p></blockquote><blockquote><p>it was like almost 5 am</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>quau&#39;s account is basically correct, he was aware i was meming but still harassed me for ~30 minutes before killing me and refusing to return my things</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>ALRIGHT ALRIGHT</p></blockquote><blockquote><p>now i know for a fact he said that he would return your stuff after memeing around about keeping it</p></blockquote><blockquote><p>now this is a simple case really. weve had cases about stolen goods and death piles before, qua i want you to return oranges stuff to a reasonable point where both parties can get to , meeting in a city half way would be best, if either party is happy to travel all the way to retrieve or deposit goods then thats a better scenario. since both of you were meming around and at some point went too far with it i wont be awarding any reparations for this case UNLESS the goods are not returned and this case is brought up again. Orange please in future learn when a meme has taken its course and gotten to far, Qua. Murder isnt a meme. point blank. if orange didnt have his home set we would have him random spawn somewhere. please in future refrain from killing an individual.</p></blockquote>',87),n=[i];function u(r,s,p,c,d,h){return o(),t("div",null,n)}const q=e(l,[["render",u]]);export{k as __pageData,q as default};
